import{_ as o,o as t,c as r,ag as s}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Overview","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),i={name:"index.md"};function n(a,e,d,l,g,c){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h1><p>Personal notes and references on software, hardware, robotics, GIS, and related topics. The site is built with <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a>; the sidebar is generated from <strong><a href="./SUMMARY.html">SUMMARY.md</a></strong> (<code>npm run docs:gen-sidebar</code>).</p><h2 id="browse-by-topic" tabindex="-1">Browse by topic <a class="header-anchor" href="#browse-by-topic" aria-label="Permalink to &quot;Browse by topic&quot;">​</a></h2><ul><li><strong>Snippets &amp; Scripts</strong> – Install scripts, backups, Magento, resize guides</li><li><strong>Software Engineering</strong> – WebAssembly, automation, Android, PHP, AWS, frontend, containers, networking, Kubernetes, tooling</li><li><strong>OBD2</strong> – Vehicle diagnostics, CAN bus, car hacking, simulators</li><li><strong>3D Printing</strong> – Gallery, problems, guides</li><li><strong>Robotics</strong> – SITL, ROS, ArduSub, PixHawk, MAVLink</li><li><strong>MicroControllers &amp; SoCs</strong> – Raspberry Pi, Arduino, ESP32</li><li><strong>Self-Hosting</strong> – Sentry, hardware</li><li><strong>GIS</strong> – Geocoding, Tile38, Deck.gl, Mapbox, Pelias</li><li><strong>Web Archiving</strong> – Awesome list</li><li><strong>IP Cameras</strong> – RTSP, ONVIF protocols</li><li><strong>Web Scraping</strong> – Monkey-DL, scrapers</li><li><strong>Pen Testing</strong> – Drones, automotive, decompilers, Kali</li><li><strong>Random</strong> – Torrents, ADHD, Chromecast, Ubuntu tips</li><li><strong>Maritime AIS</strong> – Raspberry Pi AIS research</li><li><strong>Drones</strong> – DashWare, DJI docs</li><li><strong>Software Defined Radio</strong> – Open RAN, RTL-SDR</li><li><strong>Resources</strong> – PDFs, OAuth2, pilots license</li><li><strong>MISC</strong> – AI, tutorials</li></ul><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h2><p>See <a href="./CONTRIBUTING.html">CONTRIBUTING.md</a> for how to add or edit pages.</p><h2 id="style-guide" tabindex="-1">Style Guide <a class="header-anchor" href="#style-guide" aria-label="Permalink to &quot;Style Guide&quot;">​</a></h2><p>See <a href="./.github/DOCUMENTATION-STYLE-GUIDE.html">.github/DOCUMENTATION-STYLE-GUIDE.md</a> for documentation conventions.</p><h2 id="published-site-vitepress-on-github-pages" tabindex="-1">Published site (VitePress on GitHub Pages) <a class="header-anchor" href="#published-site-vitepress-on-github-pages" aria-label="Permalink to &quot;Published site (VitePress on GitHub Pages)&quot;">​</a></h2><ul><li><strong>Prerequisites</strong>: <a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js</a> 20+ and <code>npm ci</code>.</li><li><strong>Local preview</strong>: <code>npm run docs:dev</code> (runs <code>README.md</code> → <code>index.md</code> sync, regenerates the sidebar from <code>SUMMARY.md</code>, then starts VitePress). Open the printed URL (default port <strong>5173</strong>), served at the root path <strong><code>/</code></strong>.</li><li><strong>Production build</strong>: <code>npm run docs:build</code> writes to <a href="./.vitepress/dist/"><code>.vitepress/dist/</code></a> (gitignored).</li><li><strong>GitHub Pages</strong>: pushes to <code>main</code> or <code>master</code> run <a href=".github/workflows/vitepress.yml"><code>.github/workflows/vitepress.yml</code></a>, which deploys <strong><code>.vitepress/dist</code></strong> to the <strong><code>gh-pages</code></strong> branch. In <strong>Settings → Pages</strong>, use branch <strong><code>gh-pages</code></strong> at <strong><code>/</code></strong>. The primary site URL is <a href="https://docs.f1y.ing/" target="_blank" rel="noreferrer">https://docs.f1y.ing/</a> (if no custom domain is configured, use the repository path URL for the Pages host).</li></ul><p><strong>Audit reports</strong>: <code>npm run docs:audit</code> writes <code>docs-audit-report.json</code> and <code>docs-audit-report.md</code> (gitignored); CI uploads them as a workflow artifact.</p><p>GitBook-only constructs in markdown were converted for portable rendering; see <a href="./scripts/convert_gitbook_tags.py.html"><code>scripts/convert_gitbook_tags.py</code></a> if you need similar conversions for new imports.</p>',12)])])}const u=o(i,[["render",n]]);export{h as __pageData,u as default};
